import{_ as t,o as a,c as d,ag as i}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"API-integratie","description":"","frontmatter":{},"headers":[],"relativePath":"nl/advanced/api.md","filePath":"nl/advanced/api.md"}'),n={name:"nl/advanced/api.md"};function o(r,e,l,s,c,h){return a(),d("div",null,[...e[0]||(e[0]=[i(`<h1 id="api-integratie" tabindex="-1">API-integratie <a class="header-anchor" href="#api-integratie" aria-label="Permalink to &quot;API-integratie&quot;">​</a></h1><p>Krijg programmatisch toegang tot je MyCompanyDesk-gegevens via de REST API.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>API-toegang vereist het <strong>Business</strong>-abonnement.</p></div><h2 id="overzicht" tabindex="-1">Overzicht <a class="header-anchor" href="#overzicht" aria-label="Permalink to &quot;Overzicht&quot;">​</a></h2><p>De MyCompanyDesk API stelt je in staat om:</p><ul><li>Facturen, uitgaven en klanten aan te maken en op te halen</li><li>Facturatieworkflows te automatiseren</li><li>Te integreren met andere bedrijfstools</li><li>Aangepaste rapportages te bouwen</li><li>Gegevens te synchroniseren met externe systemen</li></ul><h2 id="authenticatie" tabindex="-1">Authenticatie <a class="header-anchor" href="#authenticatie" aria-label="Permalink to &quot;Authenticatie&quot;">​</a></h2><p>Alle API-verzoeken vereisen een API-sleutel in de request-header:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Authorization: Bearer YOUR_API_KEY</span></span></code></pre></div><h3 id="een-api-sleutel-aanmaken" tabindex="-1">Een API-sleutel aanmaken <a class="header-anchor" href="#een-api-sleutel-aanmaken" aria-label="Permalink to &quot;Een API-sleutel aanmaken&quot;">​</a></h3><ol><li>Ga naar <strong>Instellingen &gt; API-sleutels</strong></li><li>Klik op <strong>Nieuwe sleutel genereren</strong></li><li>Geef de sleutel een beschrijvende naam</li><li>Kopieer de sleutel — deze wordt slechts eenmaal getoond</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Bewaar je API-sleutel veilig. Commit deze nooit naar versiebeheer en deel hem niet publiekelijk.</p></div><h2 id="basis-url" tabindex="-1">Basis-URL <a class="header-anchor" href="#basis-url" aria-label="Permalink to &quot;Basis-URL&quot;">​</a></h2><p>Alle API-endpoints zijn beschikbaar op:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api.mycompanydesk.com/api</span></span></code></pre></div><h2 id="belangrijke-endpoints" tabindex="-1">Belangrijke endpoints <a class="header-anchor" href="#belangrijke-endpoints" aria-label="Permalink to &quot;Belangrijke endpoints&quot;">​</a></h2><h3 id="klanten" tabindex="-1">Klanten <a class="header-anchor" href="#klanten" aria-label="Permalink to &quot;Klanten&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpoint</th><th>Beschrijving</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/customers</code></td><td>Alle klanten ophalen</td></tr><tr><td><code>POST</code></td><td><code>/customers</code></td><td>Een klant aanmaken</td></tr><tr><td><code>GET</code></td><td><code>/customers/:id</code></td><td>Een klant ophalen</td></tr><tr><td><code>PUT</code></td><td><code>/customers/:id</code></td><td>Een klant bijwerken</td></tr><tr><td><code>DELETE</code></td><td><code>/customers/:id</code></td><td>Een klant verwijderen</td></tr></tbody></table><h3 id="facturen" tabindex="-1">Facturen <a class="header-anchor" href="#facturen" aria-label="Permalink to &quot;Facturen&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpoint</th><th>Beschrijving</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/invoices</code></td><td>Alle facturen ophalen</td></tr><tr><td><code>POST</code></td><td><code>/invoices</code></td><td>Een factuur aanmaken</td></tr><tr><td><code>GET</code></td><td><code>/invoices/:id</code></td><td>Een factuur ophalen</td></tr><tr><td><code>PUT</code></td><td><code>/invoices/:id</code></td><td>Een factuur bijwerken</td></tr><tr><td><code>DELETE</code></td><td><code>/invoices/:id</code></td><td>Een factuur verwijderen</td></tr><tr><td><code>POST</code></td><td><code>/invoices/:id/send</code></td><td>Een factuur versturen</td></tr><tr><td><code>POST</code></td><td><code>/invoices/:id/mark-paid</code></td><td>Als betaald markeren</td></tr></tbody></table><h3 id="uitgaven" tabindex="-1">Uitgaven <a class="header-anchor" href="#uitgaven" aria-label="Permalink to &quot;Uitgaven&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpoint</th><th>Beschrijving</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/expenses</code></td><td>Alle uitgaven ophalen</td></tr><tr><td><code>POST</code></td><td><code>/expenses</code></td><td>Een uitgave aanmaken</td></tr><tr><td><code>GET</code></td><td><code>/expenses/:id</code></td><td>Een uitgave ophalen</td></tr><tr><td><code>PUT</code></td><td><code>/expenses/:id</code></td><td>Een uitgave bijwerken</td></tr><tr><td><code>DELETE</code></td><td><code>/expenses/:id</code></td><td>Een uitgave verwijderen</td></tr></tbody></table><h3 id="projecten" tabindex="-1">Projecten <a class="header-anchor" href="#projecten" aria-label="Permalink to &quot;Projecten&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpoint</th><th>Beschrijving</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/projects</code></td><td>Alle projecten ophalen</td></tr><tr><td><code>POST</code></td><td><code>/projects</code></td><td>Een project aanmaken</td></tr><tr><td><code>GET</code></td><td><code>/projects/:id</code></td><td>Een project ophalen</td></tr><tr><td><code>PUT</code></td><td><code>/projects/:id</code></td><td>Een project bijwerken</td></tr></tbody></table><h3 id="zoeken" tabindex="-1">Zoeken <a class="header-anchor" href="#zoeken" aria-label="Permalink to &quot;Zoeken&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpoint</th><th>Beschrijving</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/search?q=term&amp;type=entity</code></td><td>Zoeken over entiteiten</td></tr></tbody></table><h2 id="filteren" tabindex="-1">Filteren <a class="header-anchor" href="#filteren" aria-label="Permalink to &quot;Filteren&quot;">​</a></h2><p>Lijstendpoints ondersteunen queryparameters voor filteren:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /api/invoices?status=sent&amp;customer_id=123&amp;limit=50</span></span></code></pre></div><p>Veelgebruikte filters:</p><ul><li><code>status</code> — Filter op status</li><li><code>customer_id</code> — Filter op klant</li><li><code>project_id</code> — Filter op project</li><li><code>limit</code> — Aantal resultaten (standaard: 50)</li><li><code>offset</code> — Paginatie-offset</li></ul><h2 id="snelheidslimiet" tabindex="-1">Snelheidslimiet <a class="header-anchor" href="#snelheidslimiet" aria-label="Permalink to &quot;Snelheidslimiet&quot;">​</a></h2><p>API-verzoeken zijn beperkt in snelheid om eerlijk gebruik te garanderen:</p><ul><li>Standaard snelheidslimiet geldt per API-sleutel</li><li>Overschrijding van de limiet geeft een <code>429 Too Many Requests</code>-respons</li><li>Neem een retrystrategie op in je integratie</li></ul><h2 id="foutafhandeling" tabindex="-1">Foutafhandeling <a class="header-anchor" href="#foutafhandeling" aria-label="Permalink to &quot;Foutafhandeling&quot;">​</a></h2><p>De API retourneert standaard HTTP-statuscodes:</p><table tabindex="0"><thead><tr><th>Code</th><th>Beschrijving</th></tr></thead><tbody><tr><td><code>200</code></td><td>Geslaagd</td></tr><tr><td><code>201</code></td><td>Aangemaakt</td></tr><tr><td><code>400</code></td><td>Ongeldig verzoek (controleer je parameters)</td></tr><tr><td><code>401</code></td><td>Niet geautoriseerd (ongeldige API-sleutel)</td></tr><tr><td><code>403</code></td><td>Verboden (onvoldoende rechten)</td></tr><tr><td><code>404</code></td><td>Niet gevonden</td></tr><tr><td><code>429</code></td><td>Snelheidslimiet bereikt</td></tr><tr><td><code>500</code></td><td>Serverfout</td></tr></tbody></table><p>Foutresponsen bevatten een JSON-body:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Beschrijving van wat er mis ging&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><p>Configureer webhooks om realtime meldingen te ontvangen wanneer gebeurtenissen plaatsvinden:</p><ul><li>Factuur verstuurd</li><li>Factuur betaald</li><li>Klant aangemaakt</li><li>Uitgave toegevoegd</li></ul><p>Stel webhooks in via <strong>Instellingen &gt; API-sleutels &gt; Webhooks</strong>.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Gebruik paginatie voor grote datasets</li><li>Cache responses waar mogelijk om het aantal API-aanroepen te verminderen</li><li>Implementeer retrylogica met exponential backoff voor snelheidslimieten</li><li>Gebruik webhooks in plaats van polling voor realtime updates</li></ul>`,45)])])}const b=t(n,[["render",o]]);export{u as __pageData,b as default};
